def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    result = []
    start, end = nums[0], nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                result.append(str(start))
            else:
                result.append(f"{start}-{end}")
            start, end = num, num

    # Append the last range
    if start == end:
        result.append(str(end))
    else:
        result.append(f"{start}-{end}")

    return ', '.join(result)
